+    // --- DiagnosticStatus ---
+
+    #[test]
+    fn diagnostic_status_as_str() {
+        assert_eq!(DiagnosticStatus::Ok.as_str(), "ok");
+        assert_eq!(DiagnosticStatus::Warning.as_str(), "warning");
+        assert_eq!(DiagnosticStatus::Error.as_str(), "error");
