+    #[test]
+    fn diagnostic_status_equality() {
+        assert_eq!(DiagnosticStatus::Ok, DiagnosticStatus::Ok);
+        assert_ne!(DiagnosticStatus::Ok, DiagnosticStatus::Warning);
+        assert_ne!(DiagnosticStatus::Warning, DiagnosticStatus::Error);
