+        assert!(json.get("recommendation").is_none());
+    }
+
+    #[test]
+    fn diagnostic_check_json_warning_shape() {
+        let check = DiagnosticCheck::warning(
+            "daemon status",
+            "stale lock (PID 12345 not running)",
+            "Remove lock: rm /tmp/wa.lock",
